using System;
using System.IO;
using System.Linq;
using System.Reflection.Metadata;
using System.Reflection.PortableExecutable;

var dll = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget/packages/xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll");
using var stream = File.OpenRead(dll);
using var pe = new PEReader(stream);
var mr = pe.GetMetadataReader();

foreach (var tdh in mr.TypeDefinitions)
{
    var td = mr.GetTypeDefinition(tdh);
    var name = mr.GetString(td.Name);
    if (name == "ITestCaseOrderer")
    {
        var ns = mr.GetString(td.Namespace);
        Console.WriteLine($"Type: {ns}.{name}");
        foreach (var mh in td.GetMethods())
        {
            var md = mr.GetMethodDefinition(mh);
            Console.WriteLine($"  Method: {mr.GetString(md.Name)}");
            var sig = md.DecodeSignature(new SignatureTypeProvider(), null);
            Console.WriteLine($"    Return: {sig.ReturnType}");
            for (int i = 0; i < sig.ParameterTypes.Length; i++)
                Console.WriteLine($"    Param {i}: {sig.ParameterTypes[i]}");
        }
    }
}

class SignatureTypeProvider : ISignatureTypeProvider<string, object?>
{
    public string GetPrimitiveType(PrimitiveTypeCode typeCode) => typeCode.ToString();
    public string GetTypeFromDefinition(MetadataReader reader, TypeDefinitionHandle handle, byte rawTypeKind) { var td = reader.GetTypeDefinition(handle); return $"{reader.GetString(td.Namespace)}.{reader.GetString(td.Name)}"; }
    public string GetTypeFromReference(MetadataReader reader, TypeReferenceHandle handle, byte rawTypeKind) { var tr = reader.GetTypeReference(handle); return $"{reader.GetString(tr.Namespace)}.{reader.GetString(tr.Name)}"; }
    public string GetSZArrayType(string elementType) => $"{elementType}[]";
    public string GetGenericInstantiation(string genericType, System.Collections.Immutable.ImmutableArray<string> typeArguments) => $"{genericType}<{string.Join(", ", typeArguments)}>";
    public string GetArrayType(string elementType, ArrayShape shape) => $"{elementType}[{new string(',', shape.Rank - 1)}]";
    public string GetByReferenceType(string elementType) => $"ref {elementType}";
    public string GetPointerType(string elementType) => $"{elementType}*";
    public string GetFunctionPointerType(MethodSignature<string> signature) => "fnptr";
    public string GetGenericMethodParameter(object? genericContext, int index) => $"!!{index}";
    public string GetGenericTypeParameter(object? genericContext, int index) => $"!{index}";
    public string GetModifiedType(string modifier, string unmodifiedType, bool isRequired) => unmodifiedType;
    public string GetPinnedType(string elementType) => elementType;
    public string GetTypeFromSpecification(MetadataReader reader, object? genericContext, TypeSpecificationHandle handle, byte rawTypeKind) => "spec";
}
